from agent import *from models.products import *def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://hothardware.com/reviews', use='curl'), process_revlist, {})def process_revlist(data, context, session):    revs = data.xpath("//div[@class='cli-title']/a[@class='black p-name u-url']")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url, use='curl'), process_review, dict(context, title=title, url=url))        nexturl = data.xpath("//div[@class='pager']/a[@id='1_pager_Next']/@href").string()    if nexturl:        session.queue(Request(nexturl, use='curl'), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context['title'].split(' Review')[0]    product.ssid = context['url'].split('/')[-1]    product.category = data.xpath("//div[@class='breadcrumb']/a[@class='blue last']//text()").string()    product.url = context['url']        review = Review()    review.title = context['title']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    dates = data.xpath("//div[@class='cn-byline']/span[@class='dt-published']//text()").string().split(', ')    review.date = dates[1] + ', ' + dates[2]        authors = data.xpath("//div[@class='cn-byline']//a[@class='p-author']")    for author in authors:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))    pages = data.xpath("//div[@class='cn-pages']//select/option")    for page in pages:        page_url = context['url'] + '?page=' + page.xpath("@value").string()        page_title = page.xpath(".//text()").string()        review.properties.append(ReviewProperty(type='pages', value={'url': page_url, 'title': page_title}))        if pages:        last_url = context['url'] + '?page=' + pages.last().xpath("@value").string()        session.do(Request(last_url, use='curl'), process_review_last, dict(context, product=product, review=review))    else:        context['product'] = product        context['review'] = review        process_review_last(data, context, session)        def process_review_last(data, context, session):    product = context['product']    review = context['review']        conclusion = data.xpath("//div[@class='cn-body e-content']/h3[contains(.,'Conclusion')]/following-sibling::div//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='cn-pagetitle' and contains(.,'Final')]/following-sibling::div[@class='cn-body e-content']//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='cn-pagetitle' and contains(.,'Conclusion')]/following-sibling::div[@class='cn-body e-content']//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@class='cn-body e-content']//text()").string(multiple=True)    if conclusion:        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))        pros = data.xpath("//td[1]/ul/li//text()")    for pro in pros:        pro = pro.string().replace('+', '').strip()        if pro:            review.add_property(type='pros', value=pro)        cons = data.xpath("//td[2]/ul/li//text()")    for con in cons:        con = con.string().replace('- ', '').strip()        if con:            review.add_property(type='cons', value=con)        if conclusion:        product.reviews.append(review)        session.emit(product)